// app/Providers/AppServiceProvider.php
use Illuminate\Support\Facades\Gate;

public function boot(): void
{
    // Gate simples
    Gate::define('editar-configuracoes', function (User $user) {
        return $user->is_admin;
    });

    // Gate com recurso
    Gate::define('editar-post', function (User $user, Post $post) {
        return $user->id === $post->user_id || $user->is_admin;
    });
}

// No Controller
if (Gate::denies('editar-post', $post)) {
    abort(403);
}

// Atalho com authorize()
$this->authorize('editar-post', $post); // lança 403 se negado

// No Blade
@can('editar-post', $post)
    <a href="{{ route('posts.edit', $post) }}">Editar</a>
@endcan
